     1→<!DOCTYPE html>
     2→<html lang="ko">
     3→<head>
     4→  <meta charset="UTF-8" />
     5→  <meta name="viewport" content="width=device-width, initial-scale=1.0" />
     6→  <title>OWCS 2026 — Overwatch Champions Series</title>
     7→  <style>
     8→    @import url('https://fonts.googleapis.com/css2?family=Pretendard:wght@400;600;700;800;900&display=swap');
     9→    @import url('https://fonts.googleapis.com/css2?family=Inter:wght@400;600;700;800;900&display=swap');
    10→
    11→    *, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }
    12→
    13→    :root {
    14→      --bg: #0a0a0a;
    15→      --surface: #141414;
    16→      --surface2: #1e1e1e;
    17→      --border: #2a2a2a;
    18→      --text: #ffffff;
    19→      --text-muted: #888888;
    20→      --accent: #f97316;
    21→      --accent2: #3b82f6;
    22→      --radius: 20px;
    23→    }
    24→
    25→    html { scroll-behavior: smooth; }
    26→
    27→    body {
    28→      background: var(--bg);
    29→      color: var(--text);
    30→      font-family: 'Inter', 'Pretendard', -apple-system, sans-serif;
    31→      line-height: 1.6;
    32→      overflow-x: hidden;
    33→    }
    34→
    35→    /* NAV */
    36→    nav {
    37→      position: fixed;
    38→      top: 0;
    39→      width: 100%;
    40→      z-index: 100;
    41→      padding: 20px 40px;
    42→      display: flex;
    43→      align-items: center;
    44→      justify-content: space-between;
    45→      background: rgba(10,10,10,0.8);
    46→      backdrop-filter: blur(20px);
    47→      border-bottom: 1px solid var(--border);
    48→    }
    49→
    50→    .nav-logo {
    51→      font-size: 22px;
    52→      font-weight: 900;
    53→      letter-spacing: -0.5px;
    54→    }
    55→
    56→    .nav-logo span { color: var(--accent); }
    57→
    58→    .nav-links {
    59→      display: flex;
    60→      gap: 32px;
    61→      list-style: none;
    62→    }
    63→
    64→    .nav-links a {
    65→      color: var(--text-muted);
    66→      text-decoration: none;
    67→      font-size: 14px;
    68→      font-weight: 600;
    69→      transition: color 0.2s;
    70→    }
    71→
    72→    .nav-links a:hover { color: var(--text); }
    73→
    74→    .nav-cta {
    75→      background: var(--accent);
    76→      color: #000;
    77→      border: none;
    78→      padding: 10px 22px;
    79→      border-radius: 50px;
    80→      font-size: 14px;
    81→      font-weight: 700;
    82→      cursor: pointer;
    83→      transition: opacity 0.2s, transform 0.2s;
    84→    }
    85→
    86→    .nav-cta:hover { opacity: 0.85; transform: scale(1.03); }
    87→
    88→    /* HERO */
    89→    .hero {
    90→      min-height: 100vh;
    91→      display: flex;
    92→      flex-direction: column;
    93→      align-items: center;
    94→      justify-content: center;
    95→      text-align: center;
    96→      padding: 120px 24px 80px;
    97→      position: relative;
    98→      overflow: hidden;
    99→    }
   100→
   101→    .hero::before {
   102→      content: '';
   103→      position: absolute;
   104→      top: -200px;
   105→      left: 50%;
   106→      transform: translateX(-50%);
   107→      width: 800px;
   108→      height: 800px;
   109→      background: radial-gradient(circle, rgba(249,115,22,0.15) 0%, transparent 70%);
   110→      pointer-events: none;
   111→    }
   112→
   113→    .hero-badge {
   114→      display: inline-flex;
   115→      align-items: center;
   116→      gap: 8px;
   117→      background: rgba(249,115,22,0.12);
   118→      border: 1px solid rgba(249,115,22,0.3);
   119→      color: var(--accent);
   120→      padding: 6px 16px;
   121→      border-radius: 50px;
   122→      font-size: 13px;
   123→      font-weight: 600;
   124→      margin-bottom: 32px;
   125→    }
   126→
   127→    .hero-badge::before {
   128→      content: '';
   129→      width: 6px;
   130→      height: 6px;
   131→      background: var(--accent);
   132→      border-radius: 50%;
   133→      animation: pulse 1.5s infinite;
   134→    }
   135→
   136→    @keyframes pulse {
   137→      0%, 100% { opacity: 1; }
   138→      50% { opacity: 0.3; }
   139→    }
   140→
   141→    .hero h1 {
   142→      font-size: clamp(48px, 8vw, 96px);
   143→      font-weight: 900;
   144→      letter-spacing: -3px;
   145→      line-height: 1.0;
   146→      margin-bottom: 24px;
   147→    }
   148→
   149→    .hero h1 .highlight {
   150→      color: var(--accent);
   151→    }
   152→
   153→    .hero p {
   154→      font-size: clamp(16px, 2vw, 20px);
   155→      color: var(--text-muted);
   156→      max-width: 540px;
   157→      margin: 0 auto 48px;
   158→      line-height: 1.7;
   159→    }
   160→
   161→    .hero-buttons {
   162→      display: flex;
   163→      gap: 16px;
   164→      justify-content: center;
   165→      flex-wrap: wrap;
   166→    }
   167→
   168→    .btn-primary {
   169→      background: var(--accent);
   170→      color: #000;
   171→      border: none;
   172→      padding: 16px 36px;
   173→      border-radius: 50px;
   174→      font-size: 16px;
   175→      font-weight: 700;
   176→      cursor: pointer;
   177→      text-decoration: none;
   178→      display: inline-block;
   179→      transition: opacity 0.2s, transform 0.2s;
   180→    }
   181→
   182→    .btn-primary:hover { opacity: 0.85; transform: translateY(-2px); }
   183→
   184→    .btn-secondary {
   185→      background: var(--surface2);
   186→      color: var(--text);
   187→      border: 1px solid var(--border);
   188→      padding: 16px 36px;
   189→      border-radius: 50px;
   190→      font-size: 16px;
   191→      font-weight: 700;
   192→      cursor: pointer;
   193→      text-decoration: none;
   194→      display: inline-block;
   195→      transition: background 0.2s, transform 0.2s;
   196→    }
   197→
   198→    .btn-secondary:hover { background: var(--surface); transform: translateY(-2px); }
   199→
   200→    /* STATS */
   201→    .stats {
   202→      padding: 80px 24px;
   203→      max-width: 1100px;
   204→      margin: 0 auto;
   205→      display: grid;
   206→      grid-template-columns: repeat(auto-fit, minmax(200px, 1fr));
   207→      gap: 24px;
   208→    }
   209→
   210→    .stat-card {
   211→      background: var(--surface);
   212→      border: 1px solid var(--border);
   213→      border-radius: var(--radius);
   214→      padding: 36px 32px;
   215→      transition: transform 0.2s, border-color 0.2s;
   216→    }
   217→
   218→    .stat-card:hover {
   219→      transform: translateY(-4px);
   220→      border-color: var(--accent);
   221→    }
   222→
   223→    .stat-number {
   224→      font-size: 42px;
   225→      font-weight: 900;
   226→      letter-spacing: -2px;
   227→      color: var(--accent);
   228→    }
   229→
   230→    .stat-label {
   231→      font-size: 14px;
   232→      color: var(--text-muted);
   233→      margin-top: 8px;
   234→      font-weight: 600;
   235→    }
   236→
   237→    /* SECTION */
   238→    .section {
   239→      padding: 100px 24px;
   240→      max-width: 1100px;
   241→      margin: 0 auto;
   242→    }
   243→
   244→    .section-tag {
   245→      font-size: 13px;
   246→      font-weight: 700;
   247→      color: var(--accent);
   248→      text-transform: uppercase;
   249→      letter-spacing: 2px;
   250→      margin-bottom: 16px;
   251→    }
   252→
   253→    .section-title {
   254→      font-size: clamp(32px, 4vw, 52px);
   255→      font-weight: 900;
   256→      letter-spacing: -2px;
   257→      line-height: 1.1;
   258→      margin-bottom: 16px;
   259→    }
   260→
   261→    .section-desc {
   262→      font-size: 17px;
   263→      color: var(--text-muted);
   264→      max-width: 500px;
   265→      line-height: 1.7;
   266→      margin-bottom: 48px;
   267→    }
   268→
   269→    /* EVENTS */
   270→    .events-grid {
   271→      display: grid;
   272→      grid-template-columns: repeat(auto-fit, minmax(300px, 1fr));
   273→      gap: 20px;
   274→    }
   275→
   276→    .event-card {
   277→      background: var(--surface);
   278→      border: 1px solid var(--border);
   279→      border-radius: var(--radius);
   280→      padding: 32px;
   281→      position: relative;
   282→      overflow: hidden;
   283→      transition: transform 0.2s, border-color 0.2s;
   284→      cursor: pointer;
   285→    }
   286→
   287→    .event-card:hover {
   288→      transform: translateY(-4px);
   289→      border-color: var(--accent);
   290→    }
   291→
   292→    .event-card::before {
   293→      content: '';
   294→      position: absolute;
   295→      top: 0; left: 0; right: 0;
   296→      height: 3px;
   297→      background: var(--accent);
   298→    }
   299→
   300→    .event-card.blue::before { background: var(--accent2); }
   301→    .event-card.green::before { background: #22c55e; }
   302→
   303→    .event-month {
   304→      font-size: 12px;
   305→      font-weight: 700;
   306→      color: var(--text-muted);
   307→      text-transform: uppercase;
   308→      letter-spacing: 2px;
   309→      margin-bottom: 12px;
   310→    }
   311→
   312→    .event-name {
   313→      font-size: 22px;
   314→      font-weight: 800;
   315→      letter-spacing: -0.5px;
   316→      margin-bottom: 8px;
   317→    }
   318→
   319→    .event-location {
   320→      font-size: 14px;
   321→      color: var(--text-muted);
   322→      display: flex;
   323→      align-items: center;
   324→      gap: 6px;
   325→    }
   326→
   327→    .event-emoji { font-size: 20px; }
   328→
   329→    /* REGIONS */
   330→    .regions-grid {
   331→      display: grid;
   332→      grid-template-columns: repeat(auto-fit, minmax(240px, 1fr));
   333→      gap: 20px;
   334→    }
   335→
   336→    .region-card {
   337→      background: var(--surface);
   338→      border: 1px solid var(--border);
   339→      border-radius: var(--radius);
   340→      padding: 28px;
   341→      transition: transform 0.2s;
   342→    }
   343→
   344→    .region-card:hover { transform: translateY(-4px); }
   345→
   346→    .region-flag {
   347→      font-size: 32px;
   348→      margin-bottom: 16px;
   349→    }
   350→
   351→    .region-name {
   352→      font-size: 18px;
   353→      font-weight: 800;
   354→      margin-bottom: 12px;
   355→      letter-spacing: -0.5px;
   356→    }
   357→
   358→    .region-teams {
   359→      list-style: none;
   360→    }
   361→
   362→    .region-teams li {
   363→      font-size: 14px;
   364→      color: var(--text-muted);
   365→      padding: 6px 0;
   366→      border-bottom: 1px solid var(--border);
   367→      font-weight: 500;
   368→    }
   369→
   370→    .region-teams li:last-child { border-bottom: none; }
   371→
   372→    /* SCHEDULE */
   373→    .schedule-list {
   374→      display: flex;
   375→      flex-direction: column;
   376→      gap: 12px;
   377→    }
   378→
   379→    .schedule-item {
   380→      background: var(--surface);
   381→      border: 1px solid var(--border);
