   383→      padding: 20px 28px;
   384→      display: flex;
   385→      align-items: center;
   386→      justify-content: space-between;
   387→      flex-wrap: wrap;
   388→      gap: 12px;
   389→      transition: border-color 0.2s;
   390→    }
   391→
   392→    .schedule-item:hover { border-color: var(--accent); }
   393→
   394→    .schedule-date {
   395→      font-size: 13px;
   396→      color: var(--accent);
   397→      font-weight: 700;
   398→      min-width: 140px;
   399→    }
   400→
   401→    .schedule-name {
   402→      font-size: 16px;
   403→      font-weight: 700;
   404→      flex: 1;
   405→    }
   406→
   407→    .schedule-location {
   408→      font-size: 13px;
   409→      color: var(--text-muted);
   410→      font-weight: 600;
   411→    }
   412→
   413→    .badge {
   414→      background: rgba(249,115,22,0.15);
   415→      color: var(--accent);
   416→      padding: 4px 12px;
   417→      border-radius: 50px;
   418→      font-size: 12px;
   419→      font-weight: 700;
   420→    }
   421→
   422→    .badge.blue {
   423→      background: rgba(59,130,246,0.15);
   424→      color: var(--accent2);
   425→    }
   426→
   427→    /* PRIZE */
   428→    .prize-section {
   429→      background: var(--surface);
   430→      border: 1px solid var(--border);
   431→      border-radius: var(--radius);
   432→      padding: 60px 48px;
   433→      text-align: center;
   434→      position: relative;
   435→      overflow: hidden;
   436→    }
   437→
   438→    .prize-section::before {
   439→      content: '';
   440→      position: absolute;
   441→      bottom: -100px;
   442→      right: -100px;
