   531→  </style>
   532→</head>
   533→<body>
   534→
   535→  <!-- NAV -->
   536→  <nav>
   537→    <div class="nav-logo">OW<span>CS</span></div>
   538→    <ul class="nav-links">
   539→      <li><a href="#events">이벤트</a></li>
   540→      <li><a href="#regions">지역</a></li>
   541→      <li><a href="#schedule">일정</a></li>
   542→      <li><a href="#prize">상금</a></li>
   543→    </ul>
   544→    <button class="nav-cta">지금 시청하기</button>
