   561→
   562→  <!-- STATS -->
   563→  <div class="stats fade-up">
   564→    <div class="stat-card">
   565→      <div class="stat-number">4</div>
   566→      <div class="stat-label">참가 지역<br>NA · EMEA · Asia · China</div>
   567→    </div>
   568→    <div class="stat-card">
   569→      <div class="stat-number">11</div>
   570→      <div class="stat-label">파트너 팀<br>역대 최대 규모</div>
